import React, { useEffect, useState } from "react";
import axios from "axios";

const ClientDashboard = () => {

  const [projects, setProjects] = useState([]);
  const [totalSpent, setTotalSpent] = useState(0);
  const [pending, setPending] = useState(0);
  const [completed, setCompleted] = useState(0);

  useEffect(() => {

    const fetchProjects = async () => {
      try {
        const token = localStorage.getItem("token");

        const response = await axios.get(
          "http://localhost:5000/api/projects/client",
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        const data = response.data;

        setProjects(data);

        const completedProjects = data.filter(
          (project) => project.status === "completed"
        );

        const pendingProjects = data.filter(
          (project) => project.status === "pending"
        );

        setCompleted(completedProjects.length);
        setPending(pendingProjects.length);

        const total = completedProjects.reduce(
          (sum, project) => sum + project.budget,
          0
        );

        setTotalSpent(total);

      } catch (error) {
        console.error("Error fetching projects:", error);
      }
    };

    fetchProjects();

  }, []);   // ✅ THIS BRACKET MUST CLOSE HERE

  return (
    <div>
      <h2>Client Dashboard</h2>
      <p>Total Spent: ₹{totalSpent}</p>
      <p>Pending: {pending}</p>
      <p>Completed: {completed}</p>
    </div>
  );
};

export default ClientDashboard;
